'use client'

import { useEffect, useState } from 'react'
import Image from 'next/image'
import Link from 'next/link'
import styles from './Header.module.css'
import { publicApi } from '@/lib/api'

export default function Header() {
  const [isLive, setIsLive] = useState(false)

  useEffect(() => {
    const checkLiveStatus = async () => {
      try {
        const response = await publicApi.getLive()
        if (response.success && response.data) {
          setIsLive(response.data.isLive || false)
        }
      } catch (error) {
        console.error('Error checking live status:', error)
      }
    }

    checkLiveStatus()
    // Check every 30 seconds
    const interval = setInterval(checkLiveStatus, 30000)
    return () => clearInterval(interval)
  }, [])

  return (
    <header className={styles.header}>
      <div className={styles.container}>
        <div className={styles.logoContainer}>
          <Link href="/" className={styles.logoLink}>
            <Image
              src="/logo/chuurchlogo.jpeg"
              alt="VOSH Church Logo"
              width={80}
              height={80}
              className={styles.logo}
              priority
            />
            <div className={styles.logoText}>
              <h1 className={styles.churchName}>VOSH CHURCH INT'L</h1>
              <p className={styles.location}>KITENGELA</p>
            </div>
          </Link>
        </div>
        <nav className={styles.nav}>
          <Link href="/" className={styles.navLink}>Home</Link>
          <Link href="/about" className={styles.navLink}>About</Link>
          <Link href="/services" className={styles.navLink}>Services</Link>
          <Link href="/leadership" className={styles.navLink}>Leadership</Link>
          <Link href="/sermons" className={styles.navLink}>Sermons</Link>
          <Link href="/contact" className={styles.navLink}>Contact</Link>
          <Link href="/sermons" className={styles.liveButton}>
            {isLive && <span className={styles.liveDot}></span>}
            LIVE STREAM
          </Link>
        </nav>
      </div>
    </header>
  )
}
